      //VALUE COMPARISON SUPPORT
      public override func hashAsValue(into hasher: inout Hasher, visited complexEntities: inout Set<SDAI.ComplexEntity>) {
        super.hashAsValue(into: &hasher, visited: &complexEntities)
        self._id.value.hashAsValue(into: &hasher, visited: &complexEntities)
        self._name?.value.hashAsValue(into: &hasher, visited: &complexEntities)
        self._description?.value.hashAsValue(into: &hasher, visited: &complexEntities)
        self._definition?.value.hashAsValue(into: &hasher, visited: &complexEntities)
        self._quantity?.value.hashAsValue(into: &hasher, visited: &complexEntities)
      }

      public override func isValueEqual(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool {
        guard let rhs = rhs as? Self else { return false }
        if !super.isValueEqual(to: rhs, visited: &comppairs) { return false }
        if let comp = self._id.value.isValueEqualOptionally(to: rhs._id.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        if let comp = self._name?.value.isValueEqualOptionally(to: rhs._name?.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        if let comp = self._description?.value.isValueEqualOptionally(to: rhs._description?.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        if let comp = self._definition?.value.isValueEqualOptionally(to: rhs._definition?.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        if let comp = self._quantity?.value.isValueEqualOptionally(to: rhs._quantity?.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        return true
      }

      public override func isValueEqualOptionally(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool? {
        guard let rhs = rhs as? Self else { return false }
        var result: Bool? = true
        if let comp = super.isValueEqualOptionally(to: rhs, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._id.value.isValueEqualOptionally(to: rhs._id.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._name?.value.isValueEqualOptionally(to: rhs._name?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._description?.value.isValueEqualOptionally(to: rhs._description?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._definition?.value.isValueEqualOptionally(to: rhs._definition?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._quantity?.value.isValueEqualOptionally(to: rhs._quantity?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //MARK: WHERE RULES (ENTITY)
      public static func WHERE_wr1(SELF: ePRODUCT_DEFINITION_OCCURRENCE.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
//
        let _TEMP1 /* SDAI.LOGICAL */ = SDAI.TYPEOF( SELF.DEFINITION, IS: ePRODUCT_DEFINITION_OCCURRENCE.self )
        let _TEMP2 /* SDAI.LOGICAL */ = SDAI.TYPEOF( SELF.DEFINITION, 
          IS: ePRODUCT_DEFINITION_OCCURRENCE_REFERENCE.self )
        let _TEMP3 /* SDAI.LOGICAL */ = _TEMP1 || _TEMP2
        let _TEMP4 /* SDAI.LOGICAL */ =  !_TEMP3
        let _TEMP5 /* SDAI.LOGICAL */ = SDAI.TYPEOF( SELF, IS: ePRODUCT_DEFINITION_SPECIFIED_OCCURRENCE.self )
        let _TEMP6 /* SDAI.LOGICAL */ = _TEMP4 || _TEMP5
        return _TEMP6
      }
      public static func WHERE_wr2(SELF: ePRODUCT_DEFINITION_OCCURRENCE.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
//
        let _TEMP1 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.DEFINITION )
        let _TEMP2 /* SDAI.BAG<SDAI.GENERIC_ENTITY> */ = SDAI.USEDIN(T: SELF, 
          ROLE: \AP242_MANAGED_MODEL_BASED_3D_ENGINEERING_MIM_LF.eCONFIGURATION_DESIGN.DESIGN)
        let _TEMP3 /* SDAI.INTEGER? */ = SDAI.SIZEOF( _TEMP2 )
        let _TEMP4 /* SDAI.LOGICAL */ = _TEMP3 > SDAI.FORCE_OPTIONAL(SDAI.INTEGER(0))
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP1 || _TEMP4
        return _TEMP5
      }
      public static func WHERE_wr3(SELF: ePRODUCT_DEFINITION_OCCURRENCE.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
//
        let _TEMP1 /* SDAI.LOGICAL */ = SDAI.TYPEOF( (SELF.QUANTITY?.GROUP_REF(eMEASURE_WITH_UNIT.self))?.VALUE_COMPONENT, 
          IS: SDAI.NUMBER.self )
        let _TEMP2 /* SDAI.LOGICAL */ =  !_TEMP1
        let _TEMP3 /* eMEASURE_WITH_UNIT.PRef? */ = SELF.QUANTITY?.GROUP_REF(eMEASURE_WITH_UNIT.self)
        let _TEMP4 /* sMEASURE_VALUE? */ = _TEMP3?.VALUE_COMPONENT
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP4 > SDAI.FORCE_OPTIONAL(SDAI.INTEGER(0))
        let _TEMP6 /* SDAI.LOGICAL */ = _TEMP2 || _TEMP5
        return _TEMP6
      }

      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        ID: tIDENTIFIER, 
        NAME: tLABEL? , 
        DESCRIPTION: tTEXT? , 
        DEFINITION: sPRODUCT_DEFINITION_OR_REFERENCE_OR_OCCURRENCE? , 
        QUANTITY: eMEASURE_WITH_UNIT.PRef? 
      ) {

        self._id = ID
        self._name = NAME
        self._description = DESCRIPTION
        self._definition = DEFINITION
        self._quantity = QUANTITY

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( ID: original._id, NAME: original._name, DESCRIPTION: original._description, DEFINITION: original._definition, QUANTITY: original._quantity )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 5
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: tIDENTIFIER.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]ID for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverOptionalParameter(as: tLABEL.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]NAME for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverOptionalParameter(as: tTEXT.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]DESCRIPTION for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p3) = exchangeStructure.recoverOptionalParameter(as: 
          sPRODUCT_DEFINITION_OR_REFERENCE_OR_OCCURRENCE.self, from: parameters[3])
        else { exchangeStructure.add(errorContext: "while recovering parameter [3]DEFINITION for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p4) = exchangeStructure.recoverOptionalParameter(as: eMEASURE_WITH_UNIT.PRef.self, from: parameters[4])
        else { exchangeStructure.add(errorContext: "while recovering parameter [4]QUANTITY for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( ID: p0, NAME: p1, DESCRIPTION: p2, DEFINITION: p3, QUANTITY: p4 )
      }
    }
  }
